// Priority Task Selector for Multi-Agent Queue
// Place this Code node AFTER "Get A Task To Solve" node

// Get all tasks from previous node
const tasks = $input.all().map(item => item.json);

// If no tasks, return empty
if (tasks.length === 0) {
  return [];
}

// Sort by priority order:
// 1. test_mode = true first (DESC)
// 2. batch_priority earliest first (ASC)
// 3. sequence lowest first (ASC)
// 4. created_at earliest first (ASC) - fallback
const sortedTasks = tasks.sort((a, b) => {
  // 1. Test mode first (true > false)
  const testModeA = a.test_mode === true || a.test_mode === 'true';
  const testModeB = b.test_mode === true || b.test_mode === 'true';

  if (testModeA && !testModeB) return -1;
  if (!testModeA && testModeB) return 1;

  // 2. Batch priority (earlier timestamp first)
  if (a.batch_priority && b.batch_priority) {
    const priorityA = new Date(a.batch_priority).getTime();
    const priorityB = new Date(b.batch_priority).getTime();
    if (priorityA !== priorityB) return priorityA - priorityB;
  } else if (a.batch_priority) {
    return -1; // Has priority comes first
  } else if (b.batch_priority) {
    return 1;
  }

  // 3. Sequence (lower number first)
  const seqA = parseInt(a.sequence) || 1;
  const seqB = parseInt(b.sequence) || 1;
  if (seqA !== seqB) return seqA - seqB;

  // 4. Created at (fallback - earlier first)
  if (a.created_at && b.created_at) {
    return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
  }

  return 0;
});

// Return only the highest priority task (first after sort)
return [{ json: sortedTasks[0] }];

var finalResult = $json;
var taskInfo = $('JSON Parse').first().json; // Fallback for standard
if (!taskInfo || !taskInfo.supabase_task_id) {
    // Try Consolidated mappings if standard fails
    try { taskInfo = $('1. Parse Task').first().json; } catch(e) {}
}

var extra = taskInfo.extra || {};
var data = taskInfo.data || {};
var returnAlongWith = (extra && extra["return-along-with"]) || [];

if (returnAlongWith.length > 0) { 
  for (var key of returnAlongWith) {
    if (data.hasOwnProperty(key)) {
        finalResult[key] = data[key];
    }
  }
}

return { 
  ...taskInfo,
  "result": finalResult,
  "extra": extra,
  "data": data,
  "supabase_task_id": taskInfo.supabase_task_id || taskInfo.id
};

function convertMarkdownJsonToJsObject(partsArray) {
  const fullText = partsArray.map(part => part.text).join('');
  let trimmed = fullText.trim();

  let jsonContent;
  if (trimmed.startsWith('```json')) {
    jsonContent = trimmed.slice(7, trimmed.lastIndexOf('```')).trim();
  } else if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
    jsonContent = trimmed;
  } else {
    throw new Error('Invalid JSON format');
  }

  // Minimal cleaning - chỉ remove control chars
  jsonContent = jsonContent.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, '');

  return JSON.parse(jsonContent);
}

var partsArray = $input.first().json.candidates[0].content.parts; 
return convertMarkdownJsonToJsObject(partsArray);

const item = $input.first().json;

// Safe parse helper for JSON columns that might come as strings or objects
const parseSafe = (val, fallback) => {
    if (val === null || val === undefined) return fallback;
    if (typeof val === 'object') return val;
    try {
        let parsed = JSON.parse(val);
        // Handle potential double-stringification
        if (typeof parsed === 'string') parsed = JSON.parse(parsed);
        return parsed;
    } catch (e) {
        console.error('Parse error:', e, val);
        return fallback;
    }
};

return {
  task_id: item.task_id,
  batch_id: item.batch_id,
  user_id: item.user_id,
  task_type: item.task_type,
  prompt: item.prompt,
  extra: parseSafe(item.extra, {}),
  status: item.status,
  data: parseSafe(item.data, {}),
  ai_settings: parseSafe(item.ai_settings, {}),
  supabase_task_id: item.supabase_task_id || item.id,
  launch_id: item.launch_id || null,
  root_task_id: item.root_task_id || null,
  hierarchy_path: parseSafe(item.hierarchy_path, []),
  step_number: item.step_number || 1,
  stage_key: item.stage_key || '',
  parent_task_id: item.parent_task_id || null,
  split_group_id: item.split_group_id || null,
  test_mode: item.test_mode || false,
  requires_approval: item.requires_approval || false,
  sequence: item.sequence || null
};

const maxRetries = 3;
const currentRun = $runIndex;

if (currentRun >= maxRetries - 1) {
    throw new Error("Max retries reached. All available keys failed.");
}

// Wait a bit before retrying
return new Promise((resolve) => {
  setTimeout(() => {
    resolve([{ json: { retry: currentRun + 1 } }]);
  }, 1000);
});

// ========== PHASE 5: DETERMINE & CREATE NEXT STAGE TASKS ==========
// This node handles task chaining and parallel branching.
// Each task carries current_stage_config and next_stage_configs from the prompt-template.
// The child task's next_stage_configs will be populated by Load Batch via template lookup.

const task = $json;
const extra = task.extra || {};

// Get current stage config
const currentStageConfig = extra.current_stage_config || null;

// Get next stage configs (from prompt-template lookup in Load Batch)
const nextConfigs = extra.next_stage_configs || 
                   (extra.next_stage_config ? [extra.next_stage_config] : []);

// === TERMINATE: No next stage ===
if (!currentStageConfig || nextConfigs.length === 0) {
  return {
    action: 'terminate',
    task_id: task.supabase_task_id,
    message: 'No next stage configured - final stage reached'
  };
}

const cardinality = currentStageConfig.cardinality || 'one_to_one';
const result = task.result;
const inputData = task.data || {};

// Helper: extract stage key from template ID
// === FIXED: Sử dụng regex loại bỏ phần _step_ nếu có ===
function extractStageKey(templateId) {
  if (!templateId) return 'unknown_stage';

  // 1. Nếu có format: uuid_tênstage_step_1234
  const stepMatch = templateId.match(/^[0-9a-fA-F-]+_(.+)_step_\d+$/);
  if (stepMatch) return stepMatch[1];

  // 2. Fallback: uuid_tênstage
  const match = templateId.match(/^[0-9a-fA-F-]+_(.+)$/);
  return match ? match[1] : templateId;
}

const currentStageKey = task.stage_key || (currentStageConfig.template_id ? extractStageKey(currentStageConfig.template_id) : 'unknown_stage');
const rootId = task.root_task_id || task.supabase_task_id;
const hierarchyPath = [...(task.hierarchy_path || []), task.supabase_task_id];
const currentStepNumber = parseInt(task.step_number) || 1;

// Helper: build metadata for a new child task
function buildTaskMetadata(nextConfig, index, total, dataForTask) {
  if (!nextConfig) return null;
  const nextTplId = nextConfig.template_id || nextConfig.prompt_id;
  const nextStageKey = extractStageKey(nextTplId);

  // Parse task_type suffix
  const taskTypeMatch = nextTplId.match(/^[0-9a-f-]+_(.+)$/);
  const taskType = taskTypeMatch ? taskTypeMatch[1] : nextStageKey;

  return {
    prompt_template_id: nextTplId,
    task_type: taskType,
    input_data: dataForTask,
    parent_task_id: task.supabase_task_id,
    root_task_id: rootId,
    hierarchy_path: hierarchyPath,
    user_id: task.user_id || null,
    batch_id: nextConfig.batch_grouping === "isolated" ? null : (task.batch_id || null),
    launch_id: task.launch_id || null,
    test_mode: task.test_mode || false,
    sequence: index + 1,
    total_steps: total,
    status: 'pending',

    stage_key: nextStageKey,
    step_number: currentStepNumber + 1,
    split_group_id: task.split_group_id,
    requires_approval: nextConfig.requires_approval || task.requires_approval || false,

    // Child's extra: current_stage_config from nextConfig
    // next_stage_configs will be populated by Load Batch when this task is loaded
    extra: {
      current_stage_config: {
        template_id: nextTplId,
        cardinality: nextConfig.cardinality || 'one_to_one',
        split_path: nextConfig.split_path || null,
        split_mode: nextConfig.split_mode || 'per_item',
        output_mapping: nextConfig.output_mapping || 'result'
      },
      // next_stage_configs intentionally omitted — Load Batch will hydrate
      // from prompt_templates.next_stage_template_ids at load time
      parent_stage_key: currentStageKey,
      parent_task_id: task.supabase_task_id
    }
  };
}

// === EXECUTE BRANCHING ===
let finalTasks = [];

if (cardinality === 'one_to_one' || cardinality === '1:1') {
  finalTasks = nextConfigs.map((cfg, idx) => buildTaskMetadata(cfg, idx, 1, result)).filter(Boolean);
} else if (cardinality === "one_to_many" || cardinality === "1:N") {
  const splitPath = currentStageConfig.split_path || 'result';

  const pathParts = splitPath.split('.');
  let arrayToSplit = result;
  for (const part of pathParts) {
    if (part === 'result') continue;
    arrayToSplit = arrayToSplit?.[part];
  }

  if (!Array.isArray(arrayToSplit)) {
    return {
      action: 'terminate',
      task_id: task.supabase_task_id,
      message: `split_path '${splitPath}' did not resolve to an array`
    };
  }

  const splitMode = currentStageConfig.split_mode || 'per_item';
  for (const nextConfig of nextConfigs) {
    if (splitMode === 'per_item') {
      arrayToSplit.forEach((item, idx) => {
        finalTasks.push(buildTaskMetadata(nextConfig, idx, arrayToSplit.length, {
          ...inputData,
          user_id: task.user_id || null,
          batch_id: task.batch_id || null,
          launch_id: task.launch_id || null,
          item: item,
          _split_index: idx,
          _split_total: arrayToSplit.length
        }));
      });
    } else if (splitMode === 'per_batch') {
      const batchSize = currentStageConfig.batch_size || 10;
      for (let i = 0, bIdx = 0; i < arrayToSplit.length; i += batchSize, bIdx++) {
        const batchItems = arrayToSplit.slice(i, i + batchSize);
        finalTasks.push(buildTaskMetadata(nextConfig, bIdx, Math.ceil(arrayToSplit.length / batchSize), {
          ...inputData,
          items: batchItems,
          _batch_index: bIdx
        }));
      }
    }
  }
  finalTasks = finalTasks.filter(Boolean);
} else if (cardinality === "N:1" || cardinality === "many_to_one") {
  return {
    action: 'wait_for_merge',
    task_id: task.supabase_task_id,
    cardinality: "many_to_one",
    next_stage_configs: nextConfigs
  };
}

return {
  action: finalTasks.length > 0 ? 'create_tasks_for_branches' : 'terminate',
  tasks: finalTasks,
  total_count: finalTasks.length,
  task_id: task.supabase_task_id
};

// Node: "Create Next Stage Tasks" (Always Returns Array)
const config = $input.first().json;
const next_action = config.next_action || config.action;

// Handle terminate action - return empty array
if (next_action === 'terminate') {
  return [];  // ✅ Return empty array instead of object
}

// Handle error action
if (next_action === 'error') {
  throw new Error(config.message);
}

// === MỚI: Xử lý parallel branches ===
const tasks = config.tasks || $('Determine Next Stage').first().json.tasks || [];
if (tasks.length === 0) return [];

return tasks.map(task => ({
  prompt_template_id: task.prompt_template_id,
  task_type: task.task_type || '',
  input_data: task.input_data,
  parent_task_id: task.parent_task_id,
  root_task_id: task.root_task_id,
  hierarchy_path: task.hierarchy_path,
  batch_id: task.batch_id || null,
  user_id: task.user_id || null,
  launch_id: task.launch_id || null,
  created_at: task.created_at || null,
  started_at: task.started_at || null,
  completed_at: task.completed_at || null,
  test_mode: task.test_mode,
  sequence: task.sequence,
  total_steps: task.total_steps,
  status: task.status || 'pending',
  stage_key: task.stage_key,
  step_number: task.step_number,
  split_group_id: task.split_group_id,
  requires_approval: task.requires_approval,
  extra: task.extra
}));

// Fallback - return empty array
return [];

// Merge Pre-Process Output into input_data
const task = $('JSON Parse').first().json;
const preOutput = $json;
const preConfig = task.extra?.pre_process || {};
const outputHandling = preConfig.output_handling || 'merge';

let mergedData = { ...task.data };

if (preOutput && !preOutput.error) {
  if (outputHandling === 'replace') {
    mergedData = preOutput;
  } else if (outputHandling === 'merge') {
    mergedData = { ...mergedData, ...preOutput };
  } else if (outputHandling === 'nested') {
    const fieldName = preConfig.nested_field_name || 'pre_output';
    mergedData[fieldName] = preOutput;
  }
}

return {
  ...task,
  data: mergedData,
  _pre_process_executed: true
};

// Handle Pre-Process Failure
const task = $('JSON Parse').first().json;
const preConfig = task.extra?.pre_process || {};
const onFailure = preConfig.on_failure || 'continue';

if (onFailure === 'abort') {
  throw new Error('Pre-process webhook failed: ' + JSON.stringify($json.error));
}

// Continue with original data
return {
  ...task,
  _pre_process_failed: true,
  _pre_process_error: $json.error
};

// Handle Post-Process result
const originalResult = $('Add AlongWith Attributes').first().json;
const postConfig = $('JSON Parse').first().json.extra?.post_process || {};
const onFailure = postConfig.on_failure || 'continue';

// If post-process failed but on_failure = 'continue', proceed with original result
if ($json.error && onFailure === 'abort') {
  throw new Error('Post-process webhook failed: ' + JSON.stringify($json.error));
}

// Return original result (post-process doesn't modify task output)
return {
  ...originalResult,
  _post_process_executed: true,
  _post_process_response: $json.error ? null : $json
};

// Merge With Input - post-process that merges AI's partial output with original input
const originalTask = $('JSON Parse').first().json;
const aiResult = $('Add AlongWith Attributes').first().json;
const postConfig = originalTask.extra?.post_process || {};

const mergeKey = postConfig.merge_key || 'code';
const outputArrayPath = postConfig.merge_array_path || 'output_data';
const inputArrayPath = postConfig.input_array_path || 'output_data';

// 1. Get the full array from the original input_data
const inputData = typeof originalTask.data === 'string' 
  ? JSON.parse(originalTask.data) 
  : (originalTask.data || {});
const fullArray = inputData[inputArrayPath] || [];

// 2. Get the partial corrections from AI output
const aiOutput = aiResult.result || {};
const corrections = aiOutput[outputArrayPath] || [];

// 3. Build a lookup map from corrections
const correctionMap = new Map();
corrections.forEach(item => {
  const key = item[mergeKey];
  if (key) correctionMap.set(key, item);
});

// 4. Merge: replace items that have corrections, keep originals for the rest
const merged = fullArray.map(original => {
  const key = original[mergeKey];
  return correctionMap.has(key) ? correctionMap.get(key) : original;
});

// 5. Rebuild the result with the merged array
const mergedResult = {
  ...aiOutput,    // Keep other AI outputs like batch_info
  [outputArrayPath]: merged,
  batch_info: {
    ...(aiOutput.batch_info || {}),
    total_items: merged.length,
    corrected_items: corrections.length,
    unchanged_items: merged.length - corrections.length
  }
};

return {
  ...aiResult,
  result: mergedResult,
  _merge_applied: true,
  _merge_stats: {
    total: merged.length,
    corrected: corrections.length,
    unchanged: merged.length - corrections.length
  }
};

// 1. Lấy kết quả từ RPC call (Node ngay phía trước)
const rpcRaw = $input.first().json;
const rpcResult = Array.isArray(rpcRaw) ? rpcRaw[0] : rpcRaw;

// 2. Lấy thông tin từ node Determine Next Stage
const determineNode = $('Determine Next Stage').item.json;
const nextAction = determineNode.action;

// 3. Chuẩn bị dữ liệu task sạch
const taskStatus = {
  is_last_task: rpcResult?.is_last_task || false,
  finished_count: rpcResult?.finished_count || 0,
  total_count: rpcResult?.total_count || 0,
  next_action: nextAction
};

// 4. Logic Decision
const isStandardBranch = nextAction === 'create_tasks_for_branches';
const isLastMergeTask = ((nextAction === "wait_for_merge" || nextAction === "many_to_one") && taskStatus.is_last_task === true);

// 5. Early termination: nếu không cần đi tiếp thì dừng workflow tại đây
if (!isStandardBranch && !isLastMergeTask) {
  return []; // Terminate: chưa đủ điều kiện để tạo task tiếp theo
}

return {
  ...taskStatus,
  should_proceed: true
};

// Aggregate & Prepare Merge Task - FIXED (JSON parsing + JSONB safety)
// Input: $input.all() = completed sibling tasks from "Fetch Sibling Tasks" (Supabase rows)
// Goal: aggregate their output_data, then build tasks array for "Create Next Stage Tasks"

// 1. Get the original task context and merge config from earlier nodes
const originalTask = $('JSON Parse').first().json;
const determineResult = $('Determine Next Stage').first().json;
const nextStageConfigs = determineResult.next_stage_configs || [];

// Get merge_path from current_stage_config
const currentStageConfig = originalTask.extra?.current_stage_config || {};
const mergePath = currentStageConfig.merge_path || null;

// 2. Collect all completed sibling tasks from Fetch Sibling Tasks
const siblingTasks = $input.all().map(item => item.json);
const completedTasks = siblingTasks.filter(t => t.status === 'completed');

if (completedTasks.length === 0) {
  throw new Error('No completed sibling tasks found to merge');
}

// 3. Parse output_data safely (may be string or object from Supabase)
const allOutputs = completedTasks.map(t => {
  let data = t.output_data;
  if (typeof data === 'string') {
    try {
      data = JSON.parse(data);
    } catch (e) {
      // keep as-is if not valid JSON
    }
  }
  return data;
}).filter(d => d != null);

// 4. Aggregate based on merge_path
let aggregatedData;
if (mergePath) {
  // Extract and concatenate the specific field from each output
  aggregatedData = allOutputs.reduce((acc, curr) => {
    const val = curr?.[mergePath];
    if (Array.isArray(val)) {
      return acc.concat(val);
    } else if (val != null) {
      acc.push(val);
    }
    return acc;
  }, []);
} else {
  // No merge_path: just collect all outputs as an array
  aggregatedData = allOutputs;
}

// 5. Build the merged input_data for the next stage
const mergedInputData = mergePath
  ? { [mergePath]: aggregatedData }
  : { merged_data: aggregatedData };

// 6. Helper: extract stage key from template ID
function extractStageKey(templateId) {
  if (!templateId) return 'unknown_stage';
  const stepMatch = templateId.match(/^[0-9a-fA-F-]+_(.+)_step_\d+$/);
  if (stepMatch) return stepMatch[1];
  const match = templateId.match(/^[0-9a-fA-F-]+_(.+)$/);
  return match ? match[1] : templateId;
}

// 7. Build tasks array matching what "Create Next Stage Tasks" expects
const currentStepNumber = parseInt(originalTask.step_number) || 1;
const rootId = originalTask.root_task_id || originalTask.supabase_task_id;
const hierarchyPath = [...(originalTask.hierarchy_path || []), originalTask.supabase_task_id];
const currentStageKey = originalTask.stage_key || 'unknown_stage';

const tasks = nextStageConfigs.map((nextCfg, idx) => {
  const nextTplId = nextCfg.template_id || nextCfg.prompt_id;
  const nextStageKey = extractStageKey(nextTplId);
  const taskTypeMatch = nextTplId ? nextTplId.match(/^[0-9a-f-]+_(.+)$/) : null;
  const taskType = taskTypeMatch ? taskTypeMatch[1] : nextStageKey;

  return {
    prompt_template_id: nextTplId,
    task_type: taskType,
    input_data: mergedInputData,
    parent_task_id: originalTask.supabase_task_id,
    root_task_id: rootId,
    hierarchy_path: hierarchyPath,
    user_id: originalTask.user_id || null,
    batch_id: nextCfg.batch_grouping === 'isolated' ? null : (originalTask.batch_id || null),
    launch_id: originalTask.launch_id || null,
    test_mode: originalTask.test_mode || false,
    sequence: idx + 1,
    total_steps: nextStageConfigs.length,
    status: 'pending',
    stage_key: nextStageKey,
    step_number: currentStepNumber + 1,
    split_group_id: originalTask.split_group_id,
    requires_approval: nextCfg.requires_approval || false,
    extra: {
      current_stage_config: {
        template_id: nextTplId,
        cardinality: nextCfg.cardinality || 'one_to_one',
        split_path: nextCfg.split_path || null,
        split_mode: nextCfg.split_mode || 'per_item',
        merge_path: nextCfg.merge_path || null,
        output_mapping: nextCfg.output_mapping || 'result'
      },
      parent_stage_key: currentStageKey,
      parent_task_id: originalTask.supabase_task_id,
      _merged_from_count: completedTasks.length
    }
  };
});

// 8. Return in the format that "Create Next Stage Tasks" expects
return {
  action: tasks.length > 0 ? 'create_tasks_for_branches' : 'terminate',
  tasks: tasks,
  total_count: tasks.length,
  task_id: originalTask.supabase_task_id
};

// Call Supabase RPC: increment_finished_task
const task = $('JSON Parse').first().json;
let result = $('Input - Submit Result Phase1').first().json.result;

// Ensure result is a native object for JSONB column
if (typeof result === 'string') {
  try { result = JSON.parse(result); } catch(e) { /* keep as string if not valid JSON */ }
}

return {
  p_batch_id: task.batch_id,
  p_task_id: task.supabase_task_id,
  p_output_result: result
}
